import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"暗影提灯","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/暗影提灯.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/暗影提灯.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/暗影提灯.md"};function l(_,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"暗影提灯",tabindex:"-1"},[s("暗影提灯 "),e("a",{class:"header-anchor",href:"#暗影提灯","aria-label":'Permalink to "暗影提灯"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="暗影提灯-1" tabindex="-1">暗影提灯 <a class="header-anchor" href="#暗影提灯-1" aria-label="Permalink to &quot;暗影提灯&quot;">​</a></h1><p>暗影提灯（DARK LANTERN）<br> D+500<br> 魔幻本质<br> 这盏由暗影秘使们所设计的黑色灯笼放射出昏暗的秘术之光。<br> 描述：这件物品是一盏带着灯盖的灯笼，由秘银和黑铁细工打造而成。其上覆盖的水晶板则是色彩鲜明的金黄色。<br> 当灯点亮时，会使得周围60米范围内的环境变为昏暗（即使原本为明亮或是黑暗）。光线闪烁的比正常的火焰更慢，并且其中火焰之中发出的噼啪声更像是沉重的脚步声。<br> 激活：点亮提灯需要说出一个命令词，例如“阴影”或“黑暗”。激活灯笼是一个整轮动作。你也可以用一个标准动作打开灯盖并吹灭其中的火焰，从而中止提灯的效果，一个充满暗影能量暗影提灯可点亮8个小时，在暗影能量消耗殆尽后，提灯需要在黑暗环境内花费4个小时来重新充满。<br> 效果：暗影提灯用其秘术之光创造出昏暗环境，并可以改变四周环境光的亮度，使其变为昏暗，起效范围为半径60米的球体，这是一个D级环境来源的效果。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
